std::ios::sync_with_stdio(false), std::cin.tie(0), std::cout.tie(0);

// 更快但复杂的快读快写
int read() {
    int x = 0, w = 1;
    char ch = 0;
    while (ch &lt; '0' || ch &gt; '9')
    {
        if (ch == '-')
            w = -1;
        ch = getchar();
    }
    while (ch &gt;= '0' &amp;&amp; ch &lt;= '9')
    {
        x = x * 10 + (ch - '0');
        ch = getchar();
    }
    return x * w;
}
void write(int x) {
    if (x &lt; 0)
    {
        x = -x;
        putchar('-');
    }
    if (x &gt; 9)
        write(x / 10);
    putchar(x % 10 + '0');
}
