    inline void read(int&amp; x) {
        bool sign = 0; char ch = nc(); x = 0;
        for (; blank(ch); ch = nc());
        if (IOerror)return;
        if (ch == '-')sign = 1, ch = nc();
        for (; ch &gt;= '0' &amp;&amp; ch &lt;= '9'; ch = nc())x = x * 10 + ch - '0';
