C++<pre><code>using i64 = long long;
template&lt;class T&gt;
constexpr T power(T a, i64 b) {
    T res {1};
    for (; b; b /= 2, a *= a) {
        if (b % 2) {
            res *= a;
        }
    }
    return res;
}

constexpr i64 mul(i64 a, i64 b, i64 p) {
    i64 res = a * b - i64(1.L * a * b / p) * p;
    res %= p;
    if (res &lt; 0) {
        res += p;
    }
    return res;
}

template&lt;i64 P&gt;
struct MInt {
    i64 x;
    constexpr MInt() : x {0} {}
    constexpr MInt(i64 x) : x {norm(x % getMod())} {}

    static i64 Mod;
    constexpr static i64 getMod() {
        if (P &gt; 0) {
            return P;
        } else {
            return Mod;
        }
    }
    constexpr static void setMod(i64 Mod_) {
        Mod = Mod_;
    }
    constexpr i64 norm(i64 x) const {
        if (x &lt; 0) {
            x += getMod();
        }
        if (x &gt;= getMod()) {
            x -= getMod();
        }
        return x;
    }
    constexpr i64 val() const {
        return x;
    }
    constexpr MInt operator-() const {
        MInt res;
        res.x = norm(getMod() - x);
        return res;
    }
    constexpr MInt inv() const {
        return power(*this, getMod() - 2);
    }
    constexpr MInt &amp;operator*=(MInt rhs) &amp; {
        if (getMod() &lt; (1ULL &lt;&lt; 31)) {
            x = x * rhs.x % int(getMod());
        } else {
            x = mul(x, rhs.x, getMod());
        }
        return *this;
    }
    constexpr MInt &amp;operator+=(MInt rhs) &amp; {
        x = norm(x + rhs.x);
        return *this;
    }
    constexpr MInt &amp;operator-=(MInt rhs) &amp; {
        x = norm(x - rhs.x);
        return *this;
    }
    constexpr MInt &amp;operator/=(MInt rhs) &amp; {
        return *this *= rhs.inv();
    }
    friend constexpr MInt operator*(MInt lhs, MInt rhs) {
        MInt res = lhs;
        res *= rhs;
        return res;
    }
    friend constexpr MInt operator+(MInt lhs, MInt rhs) {
        MInt res = lhs;
        res += rhs;
        return res;
    }
    friend constexpr MInt operator-(MInt lhs, MInt rhs) {
        MInt res = lhs;
        res -= rhs;
        return res;
    }
    friend constexpr MInt operator/(MInt lhs, MInt rhs) {
        MInt res = lhs;
        res /= rhs;
        return res;
    }
    friend constexpr std::istream &amp;operator&gt;&gt;(std::istream &amp;is, MInt &amp;a) {
        i64 v;
        is &gt;&gt; v;
        a = MInt(v);
        return is;
    }
    friend constexpr std::ostream &amp;operator&lt;&lt;(std::ostream &amp;os, const MInt &amp;a) {
        return os &lt;&lt; a.val();
    }
    friend constexpr bool operator==(MInt lhs, MInt rhs) {
        return lhs.val() == rhs.val();
    }
    friend constexpr bool operator!=(MInt lhs, MInt rhs) {
        return lhs.val() != rhs.val();
    }
    friend constexpr bool operator&lt;(MInt lhs, MInt rhs) {
        return lhs.val() &lt; rhs.val();
    }
};

template&lt;&gt;
i64 MInt&lt;0&gt;::Mod = 998244353;

constexpr int P = 998244353;
using Z = MInt&lt;P&gt;;

struct Comb {
    int n;
    std::vector&lt;Z&gt; _fac;
    std::vector&lt;Z&gt; _invfac;
    std::vector&lt;Z&gt; _inv;

    Comb() : n{0}, _fac{1}, _invfac{1}, _inv{0} {}
    Comb(int n) : Comb() {
        init(n);
    }

    void init(int m) {
        m = std::min&lt;i64&gt;(m, Z::getMod() - 1);
        if (m &lt;= n) return;
        _fac.resize(m + 1);
        _invfac.resize(m + 1);
        _inv.resize(m + 1);

        for (int i = n + 1; i &lt;= m; i++) {
            _fac[i] = _fac[i - 1] * i;
        }
        _invfac[m] = _fac[m].inv();
        for (int i = m; i &gt; n; i--) {
            _invfac[i - 1] = _invfac[i] * i;
            _inv[i] = _invfac[i] * _fac[i - 1];
        }
        n = m;
    }

    Z fac(int m) {
        if (m &gt; n) init(2 * m);
        return _fac[m];
    }
    Z invfac(int m) {
        if (m &gt; n) init(2 * m);
        return _invfac[m];
    }
    Z inv(int m) {
        if (m &gt; n) init(2 * m);
        return _inv[m];
    }
    Z binom(int n, int m) {
        if (n &lt; m || m &lt; 0) return 0;
        return fac(n) * invfac(m) * invfac(n - m);
    }
} comb;
</code></pre>

