void exgcd(ll a, ll b, ll&amp; x, ll&amp; y) { // 扩欧求逆
    if (b == 0) {
        x = 1, y = 0;
        return;
    }
    exgcd(b, a % b, y, x);
    y -= a / b * x;
}
int main() {
