        // cin &gt;&gt; a[i] &gt;&gt; b[i];
        a[i] = x, b[i] = y;
        n *= a[i];
    }
    for (int i = 1; i &lt;= k; i++) {
        ll m = n / a[i];
        ll _m, y;
        exgcd(m, a[i], _m, y);
        ll c = m * _m;
        ans += (c * b[i]) % n;
        ans %= n;
    }
    long long res = (ans + n) % n;
    cout &lt;&lt; res &lt;&lt; '\n';
}
