            memcpy(t[nq].son, t[q].son, sizeof(t[q].son));
            t[nq].father = t[q].father;
            t[cur].father = t[q].father = nq;
            while (p &gt;= 0 &amp;&amp; t[p].son[c] == q)
                t[p].son[c] = nq, p = t[p].father;
        }
