vector&lt;edge&gt; ed1[N], ed2[N];
ll dis1[N], dis2[N], ans[N], a[N];
bool vis1[N], vis2[N];
int n, m, q;
void dijkstra() {
    memset(dis1, llinf, sizeof(dis1));
    memset(dis2, llinf, sizeof(dis2));
    priority_queue&lt;node, vector&lt;node&gt;, greater&lt;node&gt; &gt; q;
    q.push({0, 1});
    dis1[1] = 0;
    while (!q.empty()) {
        int u = q.top().u;
        q.pop();
        if (vis1[u]) continue;
        vis1[u] = 1;
        for (auto e : ed1[u]) {
            int v = e.v;
            ll w = e.w;
            if (dis1[v] &gt; dis1[u] + w) {
                dis1[v] = dis1[u] + w;
                q.push({dis1[v], v});
            }
        }
    }
    // 也可以使用传参的方式只写一遍，这里直接复制了
    priority_queue&lt;node, vector&lt;node&gt;, greater&lt;node&gt; &gt; qq;
    qq.push({0, n});
    dis2[n] = 0;
    while (!qq.empty()) {
        int u = qq.top().u;
        qq.pop();
        if (vis2[u]) continue;
        vis2[u] = 1;
        for (auto e : ed2[u]) {
            int v = e.v;
            ll w = e.w;
            if (dis2[v] &gt; dis2[u] + w) {
                dis2[v] = dis2[u] + w;
                qq.push({dis2[v], v});
            }
        }
    }
}
map&lt;ll, int&gt; mp;
set&lt;ll&gt; st;
ll mn = llinf;
